jQuery(function($) {

    function changeShippingLabel() {
        $('tr.woocommerce-shipping-totals.shipping th')
            .text('Shipping Charge');
            
        $('button#place_order')
            .text('অর্ডার কনফার্ম করুন');
    }

    // Run immediately
    changeShippingLabel();

    // Run after WooCommerce AJAX updates (VERY IMPORTANT)
    $(document.body).on('updated_checkout updated_cart_totals', function () {
        changeShippingLabel();
    });

});
